<template>
  <div>
    <vue-numeric-input id="style1" v-model="qty" :min="min" :max="max"></vue-numeric-input>
  </div>
</template>

<script>
import VueNumericInput from 'vue-numeric-input'

export default {
  props: {
    quantity: {
      type: [Number],
      required: true,
      default: 1
    },
    min: {
      type: [Number],
      default: 1
    },
    max: {
      type: [Number],
      default: 9999999
    },
  },
  name: "Quantity",
  data() {
    return {
      qty: this.quantity,
    }
  },
  components: {VueNumericInput}
}
</script>

<style>
#style1.vue-numeric-input.updown {
  padding-top: 1.5rem;
  padding-bottom: 1.5rem;
}

#style1.vue-numeric-input.updown .numeric-input {
  padding-right: 5px !important;
  padding-left: 5px !important;
}

#style1.vue-numeric-input.updown .btn {
  background: #6fbbff !important;
}

#style1.vue-numeric-input.updown .btn-increment {
  height: 1.5rem;
  width: 100%;
  right: 0 !important;
  left: 0 !important;
  top: 0 !important;
  bottom: auto !important;
}

#style1.vue-numeric-input.updown .btn-decrement {
  height: 1.5rem;
  width: 100%;
  left: 0 !important;
  right: 0 !important;
  top: auto !important;
  bottom: 0 !important;
}
</style>
